/**
 * amplituhedron-wire.test.ts — round-trip + rejection tests for the
 * Amplituhedron volume-cache wire codec.
 *
 * Covers the contract in `src/amplituhedron-wire.ts`:
 *   - replay round-trip (hit, payload present) with 3584-element f32
 *   - replay round-trip (miss, no payload)
 *   - capture round-trip preserves every header field
 *   - decode rejects wrong magic
 *   - decode rejects wrong version
 *   - encoded size of a 3584-element Float32Array fits under 16 KiB
 *   - bw_codec carries an fp48 integrity fingerprint (tampered payloads reject)
 */

import { describe, expect, test } from "vitest";
import {
  AMPLITUHEDRON_CONTENT_TYPE,
  AmplituhedronWireError,
  decodeCaptureRequest,
  decodeReplayResponse,
  encodeCaptureRequest,
  encodeReplayResponse,
  fingerprintFloat32Array,
} from "../src/amplituhedron-wire.js";

const QWEN_HIDDEN_DIM = 3584;

/** Deterministic pseudo-random f32 stream — small mulberry32-style LCG. */
function deterministicResidual(length: number, seed: number): Float32Array {
  const out = new Float32Array(length);
  let s = seed >>> 0;
  for (let i = 0; i < length; i++) {
    s = (s + 0x6d2b79f5) >>> 0;
    let t = s;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    const u = ((t ^ (t >>> 14)) >>> 0) / 4294967296;
    // Range ~[-1, 1] to mimic post-RMSNorm residuals (Luminary basin).
    out[i] = u * 2 - 1;
  }
  return out;
}

describe("amplituhedron-wire", () => {
  test("content type is application/x-bitwise-residual", () => {
    expect(AMPLITUHEDRON_CONTENT_TYPE).toBe("application/x-bitwise-residual");
  });

  test("replay hit round-trip preserves a 3584-element Float32Array bit-exact", () => {
    const tail = deterministicResidual(QWEN_HIDDEN_DIM, 0xa55ec0de);
    const buf = encodeReplayResponse({
      hit: true,
      tailLen: tail.length,
      kvSlabLen: 8 * 1024 * 1024,
      tailResidual: tail,
    });
    const back = decodeReplayResponse(buf);
    expect(back.hit).toBe(true);
    expect(back.tailLen).toBe(tail.length);
    expect(back.kvSlabLen).toBe(8 * 1024 * 1024);
    expect(back.tailResidual).toBeDefined();
    expect(back.tailResidual!.length).toBe(tail.length);
    for (let i = 0; i < tail.length; i++) {
      // Bitwise-identical: same f32 bit pattern → equal under ===.
      expect(back.tailResidual![i]).toBe(tail[i]);
    }
  });

  test("replay hit round-trip can carry a full prefix residual stream", () => {
    const tail = deterministicResidual(QWEN_HIDDEN_DIM, 0xa55ec0de);
    const prefix = deterministicResidual(QWEN_HIDDEN_DIM * 3, 0xbadc0de);
    const buf = encodeReplayResponse({
      hit: true,
      tailLen: tail.length,
      kvSlabLen: 8 * 1024 * 1024,
      tailResidual: tail,
      prefixResidualLen: prefix.length,
      prefixResidual: prefix,
    });
    const back = decodeReplayResponse(buf);
    expect(back.hit).toBe(true);
    expect(back.tailResidual).toBeDefined();
    expect(back.prefixResidual).toBeDefined();
    expect(back.tailFingerprint).toBe(fingerprintFloat32Array(tail));
    expect(back.prefixFingerprint).toBe(fingerprintFloat32Array(prefix));
    expect(back.prefixResidualLen).toBe(prefix.length);
    expect(back.prefixResidual!.length).toBe(prefix.length);
    for (let i = 0; i < tail.length; i++) {
      expect(back.tailResidual![i]).toBe(tail[i]);
    }
    for (let i = 0; i < prefix.length; i++) {
      expect(back.prefixResidual![i]).toBe(prefix[i]);
    }
  });

  test("replay miss round-trip carries no payload", () => {
    const buf = encodeReplayResponse({
      hit: false,
      tailLen: 0,
      kvSlabLen: 0,
    });
    const back = decodeReplayResponse(buf);
    expect(back.hit).toBe(false);
    expect(back.tailLen).toBe(0);
    expect(back.kvSlabLen).toBe(0);
    expect(back.tailResidual).toBeUndefined();
  });

  test("capture round-trip preserves all header fields", () => {
    const tail = deterministicResidual(128, 0xcafef00d);
    const args = {
      // u64 decimal string near the top of the range.
      prefixHash: "12345678901234567890",
      prefixLen: 256,
      layerLo: 0,
      layerHi: 27,
      tailResidual: tail,
    };
    const buf = encodeCaptureRequest(args);
    const back = decodeCaptureRequest(buf);
    expect(back.prefixHash).toBe(args.prefixHash);
    expect(back.prefixLen).toBe(args.prefixLen);
    expect(back.layerLo).toBe(args.layerLo);
    expect(back.layerHi).toBe(args.layerHi);
    expect(back.tailResidual.length).toBe(tail.length);
    for (let i = 0; i < tail.length; i++) {
      expect(back.tailResidual[i]).toBe(tail[i]);
    }
  });

  test("decode rejects wrong magic byte", () => {
    const tail = deterministicResidual(8, 1);
    const buf = encodeReplayResponse({
      hit: true,
      tailLen: tail.length,
      kvSlabLen: 0,
      tailResidual: tail,
    });
    // Corrupt the third magic byte ('A' → 'X').
    buf[2] = 0x58;
    expect(() => decodeReplayResponse(buf)).toThrow(AmplituhedronWireError);
  });

  test("decode rejects wrong version byte", () => {
    const tail = deterministicResidual(8, 2);
    const buf = encodeReplayResponse({
      hit: true,
      tailLen: tail.length,
      kvSlabLen: 0,
      tailResidual: tail,
    });
    // Magic occupies [0..3], version is at offset 4.
    buf[4] = 0x02;
    expect(() => decodeReplayResponse(buf)).toThrow(AmplituhedronWireError);
  });

  test("encoded size for a 3584-element Float32Array is at most 16 KiB", () => {
    const tail = deterministicResidual(QWEN_HIDDEN_DIM, 0xdeadbeef);
    const buf = encodeReplayResponse({
      hit: true,
      tailLen: tail.length,
      kvSlabLen: 0,
      tailResidual: tail,
    });
    // Raw f32 = 14336 B; bw_codec framing adds ~20 B; BWAH envelope = 14 B.
    // Net wire ~14370 B. Well under 16 KiB.
    expect(buf.length).toBeLessThanOrEqual(16 * 1024);
  });

  test("bw_codec carries fp48 integrity — tampered payload is rejected", () => {
    // 2026-05-10: the gzip-interim layer was retired; the canonical
    // bw_codec wire now carries an fp48 integrity fingerprint inside the
    // `.bw` envelope. Flipping any byte in the payload region must cause
    // decode to throw via the bw_codec integrity check.
    const tail = deterministicResidual(256, 0xfeedface);
    const buf = encodeReplayResponse({
      hit: true,
      tailLen: tail.length,
      kvSlabLen: 0,
      tailResidual: tail,
    });
    // Flip a byte deep in the bw payload (past the BWAH replay header).
    // Replay header = 14 B; pick a byte well inside the bw blob.
    const target = buf.length - 8;
    buf[target] = (buf[target]! ^ 0xff) & 0xff;
    expect(() => decodeReplayResponse(buf)).toThrow(AmplituhedronWireError);
  });
});
